def get_hip_version():
    hipconfig = shutil.which("hipconfig")
    if hipconfig is None:
        hipconfig = "/opt/rocm/bin/hipconfig"
    version = subprocess.run(
        f"{hipconfig} --version", shell=True, capture_output=True, text=True
    )
    if not version.stdout.strip():
        return parse("0.0.0")
    return parse(version.stdout.split()[-1].rstrip("-").replace("-", "+"))
